type account struct {
	Balance  int64
	Currency string
}

type transactionServer struct {
	pb.UnimplementedTransactionServiceServer
	mu              sync.Mutex
	accounts        map[string]*account
	transactionSeq  int64
}

func newTransactionServer() *transactionServer {
	return &transactionServer{
		accounts: map[string]*account{
			"acct-1": {Balance: 100000, Currency: "USD"},
			"acct-2": {Balance: 50000, Currency: "USD"},
			"acct-3": {Balance: 75000, Currency: "USD"},
		},
	}
}

func (s *transactionServer) CreateTransaction(ctx context.Context, req *pb.CreateTransactionRequest) (*pb.CreateTransactionResponse, error) {
	if req.GetFromAccountId() == "" || req.GetToAccountId() == "" {
		return nil, errors.New("from_account_id and to_account_id are required")
	}
	if req.GetFromAccountId() == req.GetToAccountId() {
		return nil, errors.New("from and to accounts must be different")
	}
	if req.GetAmount() <= 0 {
		return nil, errors.New("amount must be greater than zero")
	}
	if req.GetCurrency() == "" {
		return nil, errors.New("currency is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	from, ok := s.accounts[req.GetFromAccountId()]
	if !ok {
		return nil, errors.New("source account not found")
	}
	to, ok := s.accounts[req.GetToAccountId()]
	if !ok {
		return nil, errors.New("destination account not found")
	}
	if from.Currency != req.GetCurrency() || to.Currency != req.GetCurrency() {
		return nil, errors.New("currency mismatch")
	}
	if from.Balance < req.GetAmount() {
		return nil, errors.New("insufficient funds")
	}

	from.Balance -= req.GetAmount()
	to.Balance += req.GetAmount()
	s.transactionSeq++

	return &pb.CreateTransactionResponse{
		TransactionId: generateTransactionID(s.transactionSeq),
		Status:        "COMPLETED",
		FromBalance:   from.Balance,
		ToBalance:     to.Balance,
	}, nil
}

func (s *transactionServer) GetBalance(ctx context.Context, req *pb.GetBalanceRequest) (*pb.GetBalanceResponse, error) {
	if req.GetAccountId() == "" {
		return nil, errors.New("account_id is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	acct, ok := s.accounts[req.GetAccountId()]
	if !ok {
		return nil, errors.New("account not found")
	}

	return &pb.GetBalanceResponse{
		AccountId: req.GetAccountId(),
		Balance:   acct.Balance,
		Currency:  acct.Currency,
	}, nil
}

func generateTransactionID(seq int64) string {
	return time.Now().UTC().Format("20060102150405") + "-" + int64ToString(seq)
}

func int64ToString(v int64) string {
	if v == 0 {
		return "0"
	}
	var buf [20]byte
	i := len(buf)
	for v > 0 {
		i--
		buf[i] = byte('0' + v%10)
		v /= 10
	}
	return string(buf[i:])
}

